import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import DSATracker from './DSATracker';

function Dashboard() {
  const { currentUser, logout, loading } = useAuth();
  const { theme, toggleTheme } = useTheme();
  const [activeTab, setActiveTab]     = useState('overview');
  const [hoveredCard, setHoveredCard] = useState(null);

  useEffect(() => {
    if (!loading && !currentUser) {
      window.location.href = '/login';
    }
  }, [currentUser, loading]);

  if (loading) return (
    <div style={{ minHeight:'100vh', background: theme.bg, display:'flex', alignItems:'center', justifyContent:'center', flexDirection:'column', gap:'16px' }}>
      <div style={{ fontSize:'48px' }}>🦉</div>
      <div style={{ color:'#22c55e', fontSize:'16px', fontWeight:'500' }}>Loading your nest...</div>
    </div>
  );

  if (!currentUser) return null;

  const navItems = [
    { id: 'overview',  icon: '🏠', label: 'Overview'    },
    { id: 'dsa',       icon: '📊', label: 'DSA Tracker' },
    { id: 'github',    icon: '🐱', label: 'GitHub'      },
    { id: 'ai',        icon: '🤖', label: 'AI Mentor'   },
    { id: 'portfolio', icon: '🌐', label: 'Portfolio'   },
  ];

  const stats = [
    { icon: '📊', label: 'Problems Solved', value: '0',  sub: 'of 25 total',      color: '#22c55e', bg: 'rgba(34,197,94,0.08)',  border: 'rgba(34,197,94,0.15)',  progress: 0  },
    { icon: '🐱', label: 'GitHub Repos',    value: '--', sub: 'Connect GitHub',   color: '#3b82f6', bg: 'rgba(59,130,246,0.08)', border: 'rgba(59,130,246,0.15)', progress: 0  },
    { icon: '🔥', label: 'Day Streak',      value: '1',  sub: 'Keep it up!',      color: '#f59e0b', bg: 'rgba(245,158,11,0.08)', border: 'rgba(245,158,11,0.15)', progress: 10 },
    { icon: '🎯', label: 'Readiness Score', value: '--', sub: 'Complete profile', color: '#a855f7', bg: 'rgba(168,85,247,0.08)', border: 'rgba(168,85,247,0.15)', progress: 0  },
  ];

  const actions = [
    { icon: '📊', title: 'Start DSA Practice', desc: 'Pick up from where you left off', tab: 'dsa',       color: '#22c55e', tag: 'Most Popular' },
    { icon: '🐱', title: 'Connect GitHub',      desc: 'Sync your repos and activity',   tab: 'github',    color: '#3b82f6', tag: 'Recommended'  },
    { icon: '🤖', title: 'Get AI Roadmap',      desc: 'Personalized prep plan for you', tab: 'ai',        color: '#a855f7', tag: 'AI Powered'   },
    { icon: '🌐', title: 'View Portfolio',      desc: 'See your public profile link',   tab: 'portfolio', color: '#f59e0b', tag: 'Share Ready'  },
  ];

  return (
    <div style={{ display:'flex', minHeight:'100vh', background: theme.bg, fontFamily:"'Segoe UI', sans-serif", color: theme.text, transition:'background 0.3s, color 0.3s' }}>

      {/* Sidebar */}
      <div style={{ width:'240px', minHeight:'100vh', background: theme.sidebar, borderRight:`1px solid ${theme.sidebarBorder}`, display:'flex', flexDirection:'column', position:'fixed', top:0, left:0, bottom:0, padding:'20px 12px' }}>

        {/* Logo */}
        <div style={{ display:'flex', alignItems:'center', gap:'10px', padding:'8px 10px', marginBottom:'28px' }}>
          <div style={{ width:'36px', height:'36px', background:'rgba(34,197,94,0.1)', border:'1px solid rgba(34,197,94,0.2)', borderRadius:'10px', display:'flex', alignItems:'center', justifyContent:'center' }}>
            <span style={{ fontSize:'22px' }}>🦉</span>
          </div>
          <span style={{ fontSize:'18px', fontWeight:'700', color: theme.text, letterSpacing:'-0.3px' }}>DevNest</span>
          <span style={{ fontSize:'9px', fontWeight:'600', color:'#22c55e', background:'rgba(34,197,94,0.1)', border:'1px solid rgba(34,197,94,0.25)', borderRadius:'4px', padding:'2px 6px', letterSpacing:'1px' }}>BETA</span>
        </div>

        {/* Nav */}
        <div style={{ flex:1 }}>
          <div style={{ fontSize:'10px', fontWeight:'600', color: theme.textDim, letterSpacing:'1.5px', padding:'0 10px', marginBottom:'8px' }}>MAIN MENU</div>
          {navItems.map(item => (
            <div
              key={item.id}
              style={{
                display:'flex', alignItems:'center', gap:'10px',
                padding:'9px 10px', borderRadius:'10px', cursor:'pointer',
                color: activeTab === item.id ? theme.text : theme.textMuted,
                background: activeTab === item.id ? theme.bgThird : 'transparent',
                border: activeTab === item.id ? `1px solid ${theme.border}` : '1px solid transparent',
                marginBottom:'2px', position:'relative', transition:'all 0.15s',
              }}
              onClick={() => setActiveTab(item.id)}
            >
              <div style={{ width:'28px', height:'28px', borderRadius:'7px', background: activeTab === item.id ? 'rgba(34,197,94,0.1)' : 'transparent', display:'flex', alignItems:'center', justifyContent:'center' }}>
                <span style={{ fontSize:'14px' }}>{item.icon}</span>
              </div>
              <span style={{ fontSize:'13px', fontWeight:'500' }}>{item.label}</span>
              {activeTab === item.id && <div style={{ position:'absolute', right:'12px', width:'5px', height:'5px', borderRadius:'50%', background:'#22c55e', boxShadow:'0 0 6px #22c55e' }}></div>}
            </div>
          ))}
        </div>

        {/* Bottom */}
        <div style={{ borderTop:`1px solid ${theme.sidebarBorder}`, paddingTop:'14px' }}>
          <div style={{ display:'flex', alignItems:'center', gap:'10px', padding:'10px', background: theme.bgSecond, border:`1px solid ${theme.border}`, borderRadius:'12px', marginBottom:'8px' }}>
            <div style={{ width:'32px', height:'32px', borderRadius:'50%', background:'linear-gradient(135deg, #22c55e, #16a34a)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'13px', fontWeight:'700', color:'#000', flexShrink:0 }}>
              {currentUser.name?.charAt(0).toUpperCase()}
            </div>
            <div style={{ flex:1, minWidth:0 }}>
              <div style={{ fontSize:'12px', fontWeight:'600', color: theme.text, whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis' }}>{currentUser.name}</div>
              <div style={{ fontSize:'10px', color: theme.textDim, whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis' }}>{currentUser.email}</div>
            </div>
          </div>

          {/* Theme Toggle */}
          <button
            onClick={toggleTheme}
            style={{ width:'100%', padding:'9px', background:'transparent', border:`1px solid ${theme.border}`, borderRadius:'8px', color: theme.textMuted, fontSize:'12px', cursor:'pointer', marginBottom:'8px', display:'flex', alignItems:'center', justifyContent:'center', gap:'6px' }}
          >
            {theme.isDark ? '☀️ Light Mode' : '🌙 Dark Mode'}
          </button>

          <button
            onClick={logout}
            style={{ width:'100%', padding:'9px', background:'transparent', border:`1px solid ${theme.border}`, borderRadius:'8px', color: theme.textMuted, fontSize:'12px', cursor:'pointer' }}
          >
            → Sign out
          </button>
        </div>
      </div>

      {/* Main */}
      <div style={{ marginLeft:'240px', flex:1, padding:'32px 36px', minHeight:'100vh' }}>

        {/* Top Bar */}
        <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:'28px' }}>
          <div>
            <h1 style={{ fontSize:'22px', fontWeight:'600', color: theme.text, marginBottom:'4px' }}>
              {navItems.find(n => n.id === activeTab)?.label}
            </h1>
            <p style={{ fontSize:'12px', color: theme.textDim }}>
              {new Date().toLocaleDateString('en-US', { weekday:'long', month:'long', day:'numeric', year:'numeric' })}
            </p>
          </div>
          <div style={{ display:'flex', alignItems:'center', gap:'8px', background: theme.bgSecond, border:`1px solid ${theme.border}`, borderRadius:'999px', padding:'8px 16px', fontSize:'13px', color: theme.textMuted }}>
            <div style={{ width:'6px', height:'6px', borderRadius:'50%', background:'#22c55e', boxShadow:'0 0 6px #22c55e' }}></div>
            Welcome back, {currentUser.name?.split(' ')[0]} 👋
          </div>
        </div>

        {/* Overview */}
        {activeTab === 'overview' && (
          <div>
            {/* Stats Grid */}
            <div style={{ display:'grid', gridTemplateColumns:'repeat(4, 1fr)', gap:'14px', marginBottom:'32px' }}>
              {stats.map((stat, i) => (
                <div
                  key={stat.label}
                  style={{
                    background: hoveredCard === `stat-${i}` ? theme.bgThird : theme.bgSecond,
                    border:`1px solid ${hoveredCard === `stat-${i}` ? stat.border : theme.border}`,
                    borderRadius:'16px', padding:'20px', transition:'all 0.2s', cursor:'default',
                  }}
                  onMouseEnter={() => setHoveredCard(`stat-${i}`)}
                  onMouseLeave={() => setHoveredCard(null)}
                >
                  <div style={{ display:'flex', alignItems:'center', gap:'10px', marginBottom:'16px' }}>
                    <div style={{ width:'32px', height:'32px', borderRadius:'8px', background: stat.bg, border:`1px solid ${stat.border}`, display:'flex', alignItems:'center', justifyContent:'center' }}>
                      <span style={{ fontSize:'14px' }}>{stat.icon}</span>
                    </div>
                    <span style={{ fontSize:'11px', color: theme.textMuted, fontWeight:'500' }}>{stat.label}</span>
                  </div>
                  <div style={{ fontSize:'36px', fontWeight:'700', color: stat.color, marginBottom:'4px', lineHeight:'1' }}>{stat.value}</div>
                  <div style={{ fontSize:'11px', color: theme.textDim, marginBottom:'14px' }}>{stat.sub}</div>
                  <div style={{ height:'3px', background: theme.border, borderRadius:'999px', overflow:'hidden' }}>
                    <div style={{ height:'100%', width:`${stat.progress}%`, background: stat.color, borderRadius:'999px', boxShadow:`0 0 8px ${stat.color}50`, transition:'width 0.5s ease' }}></div>
                  </div>
                </div>
              ))}
            </div>

            {/* Quick Actions */}
            <div style={{ display:'flex', alignItems:'baseline', gap:'12px', marginBottom:'16px' }}>
              <h2 style={{ fontSize:'15px', fontWeight:'600', color: theme.text }}>Quick Actions</h2>
              <span style={{ fontSize:'12px', color: theme.textDim }}>Get started with these features</span>
            </div>

            <div style={{ display:'grid', gridTemplateColumns:'repeat(4, 1fr)', gap:'14px', marginBottom:'24px' }}>
              {actions.map((action, i) => (
                <div
                  key={action.title}
                  style={{
                    background: hoveredCard === `action-${i}` ? theme.bgThird : theme.bgSecond,
                    border:`1px solid ${hoveredCard === `action-${i}` ? action.color + '40' : theme.border}`,
                    borderRadius:'16px', padding:'20px', cursor:'pointer',
                    transition:'all 0.2s',
                    transform: hoveredCard === `action-${i}` ? 'translateY(-3px)' : 'translateY(0)',
                  }}
                  onClick={() => setActiveTab(action.tab)}
                  onMouseEnter={() => setHoveredCard(`action-${i}`)}
                  onMouseLeave={() => setHoveredCard(null)}
                >
                  <div style={{ display:'inline-block', fontSize:'9px', fontWeight:'600', letterSpacing:'0.5px', padding:'3px 8px', borderRadius:'999px', marginBottom:'14px', color: action.color, background: action.color+'15', border:`1px solid ${action.color}30` }}>
                    {action.tag}
                  </div>
                  <div style={{ width:'48px', height:'48px', borderRadius:'12px', background: action.color+'12', border:`1px solid ${action.color}25`, display:'flex', alignItems:'center', justifyContent:'center', marginBottom:'14px' }}>
                    <span style={{ fontSize:'24px' }}>{action.icon}</span>
                  </div>
                  <div style={{ fontSize:'13px', fontWeight:'600', color: theme.text, marginBottom:'6px' }}>{action.title}</div>
                  <div style={{ fontSize:'11px', color: theme.textMuted, lineHeight:'1.5', marginBottom:'16px' }}>{action.desc}</div>
                  <div style={{ fontSize:'12px', fontWeight:'600', color: action.color }}>Explore →</div>
                </div>
              ))}
            </div>

            {/* Banner */}
            <div style={{ background:'linear-gradient(135deg, rgba(34,197,94,0.08), rgba(59,130,246,0.06))', border:'1px solid rgba(34,197,94,0.15)', borderRadius:'16px', padding:'20px 24px', display:'flex', alignItems:'center', justifyContent:'space-between', gap:'20px' }}>
              <div>
                <div style={{ fontSize:'14px', fontWeight:'600', color: theme.text, marginBottom:'4px' }}>🚀 Complete your profile to unlock all features</div>
                <div style={{ fontSize:'12px', color: theme.textMuted }}>Add your GitHub username and LeetCode handle to get started</div>
              </div>
              <button
                style={{ padding:'10px 20px', background:'linear-gradient(135deg, #22c55e, #16a34a)', border:'none', borderRadius:'10px', color:'#000', fontSize:'12px', fontWeight:'700', cursor:'pointer', whiteSpace:'nowrap', boxShadow:'0 4px 14px rgba(34,197,94,0.25)' }}
                onClick={() => setActiveTab('github')}
              >
                Complete Profile →
              </button>
            </div>
          </div>
        )}

        {/* DSA Tab */}
        {activeTab === 'dsa' && <DSATracker theme={theme} />}

        {/* Coming Soon */}
        {activeTab !== 'overview' && activeTab !== 'dsa' && (
          <div style={{ display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', minHeight:'65vh', gap:'14px', position:'relative' }}>
            <div style={{ position:'absolute', width:'300px', height:'300px', background:'radial-gradient(circle, rgba(34,197,94,0.06) 0%, transparent 70%)', borderRadius:'50%', pointerEvents:'none' }}></div>
            <div style={{ fontSize:'52px' }}>{navItems.find(n => n.id === activeTab)?.icon}</div>
            <h2 style={{ fontSize:'20px', fontWeight:'600', color: theme.text }}>{navItems.find(n => n.id === activeTab)?.label}</h2>
            <p style={{ fontSize:'13px', color: theme.textMuted }}>This section is under construction. Coming soon!</p>
            <button style={{ padding:'10px 20px', background:'transparent', border:`1px solid ${theme.border}`, borderRadius:'8px', color: theme.textMuted, fontSize:'13px', cursor:'pointer', marginTop:'8px' }} onClick={() => setActiveTab('overview')}>← Back to Overview</button>
          </div>
        )}
      </div>

      <style>{`
        * { box-sizing: border-box; }
        ::-webkit-scrollbar { width: 4px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: #2a2a2a; border-radius: 2px; }
      `}</style>
    </div>
  );
}

export default Dashboard;
